                code: "# ขั้นที่ 1: ตรวจว่า GPO link อยู่และ enabled\nGet-GPLink -Target 'OU=Users,OU=Company,DC=corp,DC=local'\n# ดู LinkEnabled — ต้องเป็น True\n\n# ขั้นที่ 2: ตรวจ Security Filtering\nGet-GPPermission -Name 'Policy-MappedDrives' -All\n# ต้องมี 'Authenticated Users' หรือ group ที่ user นั้นอยู่ด้วย GpoApply\n\n# ขั้นที่ 3: ตรวจว่า user/computer อยู่ใน OU ที่ link แล้ว\nGet-ADUser -Identity 'somchai.j' | Select DistinguishedName\n# DistinguishedName ต้องอยู่ใต้ OU ที่ GPO link\n\n# ขั้นที่ 4: ตรวจ gpresult บน client\ngpresult /r 2>&1\n# ดูในส่วน 'DENIED GPOs' — ถ้ามีชื่อ GPO อยู่นี่แสดงว่า filter ไม่ผ่าน\n\n# ขั้นที่ 5: ตรวจ Loopback Processing (ถ้าใช้)\n# Computer Configuration → Administrative Templates → System → Group Policy\n# → Configure user Group Policy loopback processing mode\n\n# ขั้นที่ 6: ดู Event Log\nGet-WinEvent -LogName 'System' | \n    Where-Object { $_.ProviderName -eq 'GroupPolicy' } | \n    Select TimeCreated, Id, Message -First 20\n\n# Event ID สำคัญ:\n# 1500 = Computer policy applied successfully\n# 1501 = User policy applied successfully  \n# 1006 = Computer policy error\n# 1085 = Extension failed (เช่น Software Installation fail)\n\n# ขั้นที่ 7: ตรวจ WMI Filter (ถ้ามี)\nGet-GPO -Name 'Policy-MappedDrives' | Select WmiFilter\n# ถ้ามี WMI Filter ให้ตรวจว่า query นั้น match กับเครื่อง client จริง",
