                code: "# สร้างโครงสร้างโฟลเดอร์บน D:\\\n$basePath = 'D:\\FileServer'\n\n$folders = @(\n    # โฟลเดอร์กลางแชร์ทั้งองค์กร\n    'Shared\\Public',           # ทุกคนอ่านได้ ไม่มีใครเขียน\n    'Shared\\Announcements',    # HR เขียน ทุกคนอ่าน\n\n    # โฟลเดอร์แยกตามแผนก\n    'Departments\\Finance',\n    'Departments\\HR',\n    'Departments\\IT',\n    'Departments\\Management',\n\n    # โฟลเดอร์ส่วนกลางระหว่างแผนก\n    'Exchange',                # Drop zone แลกไฟล์ข้ามแผนก\n\n    # Home folder ของแต่ละ user\n    'Users'\n)\n\nforeach ($f in $folders) {\n    $path = Join-Path $basePath $f\n    if (-not (Test-Path $path)) {\n        New-Item -Path $path -ItemType Directory | Out-Null\n        Write-Host \"Created: $path\"\n    }\n}\n\nGet-ChildItem $basePath -Recurse -Directory | Select FullName",
