                code: "# รันบน Domain Controller\n$ouGroups = 'OU=Groups,OU=Company,DC=corp,DC=local'\n\n# สร้าง group สำหรับแต่ละแผนก — แยก Read กับ ReadWrite\n$groups = @(\n    @{ Name='FS-Finance-RW';     Desc='Finance folder - Read/Write' },\n    @{ Name='FS-Finance-RO';     Desc='Finance folder - Read Only' },\n    @{ Name='FS-HR-RW';          Desc='HR folder - Read/Write' },\n    @{ Name='FS-HR-RO';          Desc='HR folder - Read Only' },\n    @{ Name='FS-IT-RW';          Desc='IT folder - Read/Write' },\n    @{ Name='FS-Management-RW';  Desc='Management folder - Read/Write' },\n    @{ Name='FS-Exchange-RW';    Desc='Exchange drop zone - Read/Write' },\n    @{ Name='FS-Public-RO';      Desc='Public folder - Read Only' }\n)\n\nforeach ($g in $groups) {\n    New-ADGroup `\n        -Name $g.Name `\n        -GroupScope Global `\n        -GroupCategory Security `\n        -Path $ouGroups `\n        -Description $g.Desc\n}\n\n# เพิ่ม user เข้า group ตามแผนก\nAdd-ADGroupMember -Identity 'FS-Finance-RW' -Members 'malee.s','finance02'\nAdd-ADGroupMember -Identity 'FS-HR-RW'      -Members 'hr01','hr02'\nAdd-ADGroupMember -Identity 'FS-IT-RW'      -Members 'somchai.j','napat.j'\n\n# IT Admin เข้าได้ทุก folder (สำหรับ support)\nAdd-ADGroupMember -Identity 'FS-Finance-RO'    -Members 'GRP-IT-Admin'\nAdd-ADGroupMember -Identity 'FS-HR-RO'         -Members 'GRP-IT-Admin'\nAdd-ADGroupMember -Identity 'FS-Exchange-RW'   -Members 'Domain Users'\nAdd-ADGroupMember -Identity 'FS-Public-RO'     -Members 'Domain Users'",
