                code: "# ฟังก์ชัน icacls ตั้งตรง ๆ ง่ายกว่าสำหรับ batch\n\n# โฟลเดอร์ Finance\nicacls 'D:\\FileServer\\Departments\\Finance' /inheritance:d  # ตัด inheritance\nicacls 'D:\\FileServer\\Departments\\Finance' /remove 'Users'\nicacls 'D:\\FileServer\\Departments\\Finance' /grant 'CORP\\FS-Finance-RW:(OI)(CI)M'\nicacls 'D:\\FileServer\\Departments\\Finance' /grant 'CORP\\FS-Finance-RO:(OI)(CI)RX'\nicacls 'D:\\FileServer\\Departments\\Finance' /grant 'BUILTIN\\Administrators:(OI)(CI)F'\n\n# โฟลเดอร์ HR\nicacls 'D:\\FileServer\\Departments\\HR' /inheritance:d\nicacls 'D:\\FileServer\\Departments\\HR' /remove 'Users'\nicacls 'D:\\FileServer\\Departments\\HR' /grant 'CORP\\FS-HR-RW:(OI)(CI)M'\nicacls 'D:\\FileServer\\Departments\\HR' /grant 'CORP\\FS-HR-RO:(OI)(CI)RX'\nicacls 'D:\\FileServer\\Departments\\HR' /grant 'BUILTIN\\Administrators:(OI)(CI)F'\n\n# โฟลเดอร์ IT\nicacls 'D:\\FileServer\\Departments\\IT' /inheritance:d\nicacls 'D:\\FileServer\\Departments\\IT' /remove 'Users'\nicacls 'D:\\FileServer\\Departments\\IT' /grant 'CORP\\FS-IT-RW:(OI)(CI)M'\nicacls 'D:\\FileServer\\Departments\\IT' /grant 'BUILTIN\\Administrators:(OI)(CI)F'\n\n# โฟลเดอร์ Public — ทุกคนอ่านได้ ไม่มีใครเขียน\nicacls 'D:\\FileServer\\Shared\\Public' /inheritance:d\nicacls 'D:\\FileServer\\Shared\\Public' /grant 'CORP\\Domain Users:(OI)(CI)RX'\nicacls 'D:\\FileServer\\Shared\\Public' /grant 'BUILTIN\\Administrators:(OI)(CI)F'\n\n# โฟลเดอร์ Exchange — ทุกคน read/write แต่ลบไฟล์คนอื่นไม่ได้\nicacls 'D:\\FileServer\\Exchange' /inheritance:d\nicacls 'D:\\FileServer\\Exchange' /grant 'CORP\\Domain Users:(OI)(CI)M'\nicacls 'D:\\FileServer\\Exchange' /grant 'BUILTIN\\Administrators:(OI)(CI)F'\n\n# ตรวจสอบ\nicacls 'D:\\FileServer\\Departments\\Finance'",
