                code: "# สร้าง Home folder ให้ user ทุกคนพร้อมกัน\n$users = Get-ADUser -Filter * `\n    -SearchBase 'OU=Users,OU=Company,DC=corp,DC=local' | \n    Select SamAccountName\n\nforeach ($user in $users) {\n    $username = $user.SamAccountName\n    $homePath = \"D:\\FileServer\\Users\\$username\"\n\n    # สร้างโฟลเดอร์\n    if (-not (Test-Path $homePath)) {\n        New-Item -Path $homePath -ItemType Directory | Out-Null\n    }\n\n    # ตั้ง NTFS — เฉพาะ user นั้นและ Admin เท่านั้น\n    icacls $homePath /inheritance:d\n    icacls $homePath /remove 'Users'\n    icacls $homePath /grant \"CORP\\$username`:(OI)(CI)F\"\n    icacls $homePath /grant 'BUILTIN\\Administrators:(OI)(CI)F'\n\n    # ผูก Home folder กับ AD User — map เป็น H: ตอน login\n    Set-ADUser -Identity $username `\n        -HomeDirectory \"\\\\srv-file\\Users\\$username\" `\n        -HomeDrive 'H:'\n\n    Write-Host \"Created home folder for: $username\"\n}\n\n# ตรวจสอบ\nGet-ADUser -Filter * -SearchBase 'OU=Users,OU=Company,DC=corp,DC=local' `\n    -Properties HomeDirectory, HomeDrive | \n    Select Name, HomeDirectory, HomeDrive",
