                code: "# สร้าง GPO สำหรับ WSUS client\nNew-GPO -Name 'Policy-WSUS-Client' -Comment 'WSUS client configuration'\n\n# ชี้ client ไปที่ WSUS server\nSet-GPRegistryValue `\n    -Name 'Policy-WSUS-Client' `\n    -Key 'HKLM\\Software\\Policies\\Microsoft\\Windows\\WindowsUpdate' `\n    -ValueName 'WUServer' `\n    -Type String `\n    -Value 'http://srv-wsus.corp.local:8530'\n\nSet-GPRegistryValue `\n    -Name 'Policy-WSUS-Client' `\n    -Key 'HKLM\\Software\\Policies\\Microsoft\\Windows\\WindowsUpdate' `\n    -ValueName 'WUStatusServer' `\n    -Type String `\n    -Value 'http://srv-wsus.corp.local:8530'\n\n# เปิดใช้งาน WSUS (UseWUServer = 1)\nSet-GPRegistryValue `\n    -Name 'Policy-WSUS-Client' `\n    -Key 'HKLM\\Software\\Policies\\Microsoft\\Windows\\WindowsUpdate\\AU' `\n    -ValueName 'UseWUServer' `\n    -Type DWord `\n    -Value 1\n\n# กำหนด target group (client จัดตัวเองเข้า group)\nSet-GPRegistryValue `\n    -Name 'Policy-WSUS-Client' `\n    -Key 'HKLM\\Software\\Policies\\Microsoft\\Windows\\WindowsUpdate' `\n    -ValueName 'TargetGroupEnabled' `\n    -Type DWord `\n    -Value 1\n\n# ** สร้าง GPO แยกตาม group **\n# GPO สำหรับ Ring1: TargetGroup = Ring1-Test\n# GPO สำหรับ Ring3: TargetGroup = Ring3-Production\nSet-GPRegistryValue `\n    -Name 'Policy-WSUS-Client' `\n    -Key 'HKLM\\Software\\Policies\\Microsoft\\Windows\\WindowsUpdate' `\n    -ValueName 'TargetGroup' `\n    -Type String `\n    -Value 'Ring3-Production'\n\n# ตั้ง Auto Update behavior\nSet-GPRegistryValue `\n    -Name 'Policy-WSUS-Client' `\n    -Key 'HKLM\\Software\\Policies\\Microsoft\\Windows\\WindowsUpdate\\AU' `\n    -ValueName 'AUOptions' `\n    -Type DWord `\n    -Value 4\n    # 2 = Notify only\n    # 3 = Auto download, notify install\n    # 4 = Auto download and schedule install\n    # 5 = Allow local admin to choose\n\n# กำหนดเวลา install — ทุกวันอังคาร 02:00\nSet-GPRegistryValue `\n    -Name 'Policy-WSUS-Client' `\n    -Key 'HKLM\\Software\\Policies\\Microsoft\\Windows\\WindowsUpdate\\AU' `\n    -ValueName 'ScheduledInstallDay' `\n    -Type DWord `\n    -Value 3\n    # 0=Every day, 1=Sunday, 2=Monday, 3=Tuesday ... 7=Saturday\n\nSet-GPRegistryValue `\n    -Name 'Policy-WSUS-Client' `\n    -Key 'HKLM\\Software\\Policies\\Microsoft\\Windows\\WindowsUpdate\\AU' `\n    -ValueName 'ScheduledInstallTime' `\n    -Type DWord `\n    -Value 2  # 2 = 02:00 AM\n\n# Link GPO ไปยัง domain\nNew-GPLink `\n    -Name 'Policy-WSUS-Client' `\n    -Target 'DC=corp,DC=local'\n\n# Force update บน client\ngpupdate /force\nwuauclt /detectnow\nwuauclt /reportnow",
