                code: "# WSUS Server Cleanup Wizard ผ่าน PowerShell\n$wsus = [Microsoft.UpdateServices.Administration.AdminProxy]::GetUpdateServer('localhost', $false, 8530)\n\n$cleanupScope = New-Object Microsoft.UpdateServices.Administration.CleanupScope\n\n# เลือกสิ่งที่ต้องการ cleanup\n$cleanupScope.DeclineSupersededUpdates   = $true  # ปฏิเสธ patch ที่มีตัวใหม่แทนแล้ว\n$cleanupScope.DeclineExpiredUpdates      = $true  # ปฏิเสธ patch หมดอายุ\n$cleanupScope.CleanupObsoleteUpdates     = $true  # ลบ patch ที่ declined\n$cleanupScope.CompressUpdates            = $true  # บีบอัด update metadata\n$cleanupScope.CleanupObsoleteComputers   = $true  # ลบ computer ที่ไม่ได้ sync นาน\n$cleanupScope.CleanupUnneededContentFiles = $true # ลบไฟล์ content ที่ไม่มีใคร approved\n\n$cleanupManager = $wsus.GetCleanupManager()\n$result = $cleanupManager.PerformCleanup($cleanupScope)\n\nWrite-Host \"Disk space freed: $([math]::Round($result.DiskSpaceFreed / 1GB, 2)) GB\"\nWrite-Host \"Obsolete updates removed: $($result.ObsoleteUpdatesDeleted)\"\nWrite-Host \"Expired updates declined: $($result.ExpiredUpdatesDeclined)\"\n\n# ตั้ง Task Scheduler รัน cleanup อัตโนมัติทุกเดือน\n$action = New-ScheduledTaskAction `\n    -Execute 'PowerShell.exe' `\n    -Argument '-NonInteractive -File C:\\Scripts\\WSUS-Cleanup.ps1'\n\n$trigger = New-ScheduledTaskTrigger `\n    -Weekly `\n    -WeeksInterval 4 `\n    -DaysOfWeek Sunday `\n    -At '03:00AM'\n\nRegister-ScheduledTask `\n    -TaskName 'WSUS Monthly Cleanup' `\n    -Action $action `\n    -Trigger $trigger `\n    -RunLevel Highest `\n    -User 'SYSTEM'",
