                code: "# ตั้งชื่อ interface ให้ชัดเจนก่อน\n/interface set ether1 name=WAN\n/interface set ether2 name=TRUNK\n\n# สร้าง VLAN interface บน TRUNK port\n/interface vlan add name=vlan10-office  vlan-id=10 interface=TRUNK\n/interface vlan add name=vlan20-server  vlan-id=20 interface=TRUNK\n/interface vlan add name=vlan30-guest   vlan-id=30 interface=TRUNK\n\n# ตรวจสอบ VLAN interface ที่สร้าง\n/interface vlan print\n# ควรเห็น:\n# NAME           MTU   ARP       VLAN-ID  INTERFACE\n# vlan10-office  1500  enabled   10       TRUNK\n# vlan20-server  1500  enabled   20       TRUNK\n# vlan30-guest   1500  enabled   30       TRUNK\n\n# ตั้ง IP gateway สำหรับแต่ละ VLAN\n/ip address add address=192.168.10.1/24 interface=vlan10-office comment=\"VLAN10 Office Gateway\"\n/ip address add address=192.168.20.1/24 interface=vlan20-server comment=\"VLAN20 Server Gateway\"\n/ip address add address=192.168.30.1/24 interface=vlan30-guest  comment=\"VLAN30 Guest Gateway\"\n\n# ตรวจสอบ IP\n/ip address print\n# ควรเห็น IP บนแต่ละ VLAN interface",
