                code: "# ========================================\n# VLAN 10 — Office (192.168.10.0/24)\n# ========================================\n/ip pool add name=pool-vlan10 ranges=192.168.10.100-192.168.10.200\n/ip dhcp-server add \\\n    name=dhcp-vlan10 \\\n    interface=vlan10-office \\\n    address-pool=pool-vlan10 \\\n    lease-time=8h \\\n    disabled=no\n/ip dhcp-server network add \\\n    address=192.168.10.0/24 \\\n    gateway=192.168.10.1 \\\n    dns-server=192.168.10.1,8.8.8.8 \\\n    comment=\"VLAN10 Office\"\n\n# ========================================\n# VLAN 20 — Server (192.168.20.0/24)\n# ========================================\n# Server ใช้ IP static เป็นส่วนใหญ่\n# ตั้ง DHCP pool เล็กไว้สำหรับ device ชั่วคราว\n/ip pool add name=pool-vlan20 ranges=192.168.20.200-192.168.20.220\n/ip dhcp-server add \\\n    name=dhcp-vlan20 \\\n    interface=vlan20-server \\\n    address-pool=pool-vlan20 \\\n    lease-time=12h \\\n    disabled=no\n/ip dhcp-server network add \\\n    address=192.168.20.0/24 \\\n    gateway=192.168.20.1 \\\n    dns-server=192.168.20.1,8.8.8.8 \\\n    comment=\"VLAN20 Server\"\n\n# ========================================\n# VLAN 30 — Guest (192.168.30.0/24)\n# ========================================\n/ip pool add name=pool-vlan30 ranges=192.168.30.100-192.168.30.250\n/ip dhcp-server add \\\n    name=dhcp-vlan30 \\\n    interface=vlan30-guest \\\n    address-pool=pool-vlan30 \\\n    lease-time=2h \\\n    disabled=no\n/ip dhcp-server network add \\\n    address=192.168.30.0/24 \\\n    gateway=192.168.30.1 \\\n    dns-server=8.8.8.8,1.1.1.1 \\\n    comment=\"VLAN30 Guest\"\n# Guest ใช้ external DNS ตรงๆ ไม่ผ่าน router\n\n# ตรวจสอบ DHCP server ทั้งหมด\n/ip dhcp-server print\n/ip dns set servers=8.8.8.8,1.1.1.1 allow-remote-requests=yes",
