                code: "# ========================================\n# สร้าง IP Pool\n# ========================================\n/ip pool add \\\n    name=pool-lan \\\n    ranges=192.168.1.100-192.168.1.200 \\\n    comment=\"LAN DHCP Pool\"\n\n# ตรวจสอบ pool\n/ip pool print\n# ดู used — จำนวน IP ที่ถูกใช้ไปแล้ว\n\n# ========================================\n# สร้าง DHCP Server\n# ========================================\n/ip dhcp-server add \\\n    name=dhcp-lan \\\n    interface=LAN \\\n    address-pool=pool-lan \\\n    lease-time=12h \\\n    disabled=no \\\n    comment=\"Main LAN DHCP Server\"\n\n# ========================================\n# ตั้ง DHCP Network — ส่ง option ให้ client\n# ========================================\n/ip dhcp-server network add \\\n    address=192.168.1.0/24 \\\n    gateway=192.168.1.1 \\\n    dns-server=192.168.1.1,8.8.8.8 \\\n    ntp-server=192.168.1.1 \\\n    domain=office.local \\\n    comment=\"LAN Network Options\"\n\n# เปิด DNS resolver บน router\n/ip dns set \\\n    servers=8.8.8.8,1.1.1.1 \\\n    allow-remote-requests=yes\n\n# ตรวจสอบ\n/ip dhcp-server print\n/ip dhcp-server network print",
