                code: "# Option มาตรฐานที่ตั้งใน network block ได้เลย\n# (ตั้งแล้วจาก step ก่อน)\n# gateway    = option 3\n# dns-server = option 6\n# domain     = option 15\n# ntp-server = option 42\n\n# ========================================\n# เพิ่ม Option เพิ่มเติมด้วย DHCP Option Sets\n# ========================================\n\n# สร้าง option set\n/ip dhcp-server option add \\\n    name=opt-tftp \\\n    code=66 \\\n    value=\"'192.168.1.5'\" \\\n    comment=\"TFTP Server สำหรับ PXE Boot\"\n\n/ip dhcp-server option add \\\n    name=opt-bootfile \\\n    code=67 \\\n    value=\"'pxelinux.0'\" \\\n    comment=\"PXE Boot filename\"\n\n# รวม option หลายตัวเป็น option set\n/ip dhcp-server option sets add \\\n    name=pxe-options \\\n    options=opt-tftp,opt-bootfile\n\n# ผูก option set กับ DHCP server\n/ip dhcp-server set dhcp-lan dhcp-option-set=pxe-options\n\n# ========================================\n# Option สำหรับ VoIP Phone (ตัวอย่าง)\n# ========================================\n/ip dhcp-server option add \\\n    name=opt-voip-server \\\n    code=160 \\\n    value=\"'http://192.168.1.10:8080/provision'\" \\\n    comment=\"VoIP Provisioning URL\"\n\n# ดู option ทั้งหมดที่มี\n/ip dhcp-server option print\n/ip dhcp-server option sets print",
